<script> // 🔥 HASH CORE (mais estável e distribuído)
const hashStr = s => {
  let h = 0xdeadbeef;
  for (let i = 0; i < s.length; i++) {
    h = Math.imul(h ^ s.charCodeAt(i), 2654435761);
  }
  return (h ^ (h >>> 16)) >>> 0;
};

// 🔥 STYLE INJECTOR (idempotente)
function injectOrbStyles() {
  if (document.getElementById('dual-orb-styles')) return;

  const style = document.createElement('style');
  style.id = 'dual-orb-styles';
  style.innerHTML = `
    @keyframes orbBreathe {
      0%,100% { transform: scale(1); opacity:.85; filter:brightness(1); }
      50% { transform: scale(1.08); opacity:1; filter:brightness(1.3); }
    }
    @keyframes orbSpin {
      from { transform: rotate(0deg); }
      to { transform: rotate(360deg); }
    }
    @keyframes orbPulse {
      0% { transform: scale(.7); opacity:.5; }
      100% { transform: scale(1.3); opacity:0; }
    }

    .dual-orb {
      cursor:pointer;
      transition:transform .3s cubic-bezier(.175,.885,.32,1.275);
    }
    .dual-orb:active { transform:scale(.9); }

    .orb-glow {
      animation: orbBreathe var(--orb-speed,4s) ease-in-out infinite;
      transform-origin:center;
    }
    .orb-ring {
      animation: orbSpin var(--orb-spin-speed,12s) linear infinite;
      transform-origin:center;
    }
    .orb-pulse {
      animation: orbPulse var(--orb-pulse-speed,2s) cubic-bezier(.2,.8,.2,1) infinite;
      transform-origin:center;
    }

    .dual-orb:hover .orb-glow { animation-duration:1.5s!important; }
    .dual-orb:hover .orb-ring { animation-duration:4s!important; }
    .dual-orb:hover .orb-pulse { animation-duration:1s!important; }
  `;
  document.head.appendChild(style);
}

// 🔥 UNIVERSAL ORB GENERATOR (FINAL FUSION)
function makeOrbAvatar(name = 'DUAL', size = 64) {
  injectOrbStyles();

  const seed = hashStr(name || 'DUAL');

  // 🎨 HUE derivado + fallback pro tema
  const baseHue = seed % 360;
  const accentHue = (seed * 1.618) % 360;

  // usa variável global se quiser forçar cor do sistema
  const usePrimary = getComputedStyle(document.documentElement)
    .getPropertyValue('--kob-voice-primary')
    .trim();

  const h1 = usePrimary ? null : baseHue;
  const h2 = usePrimary ? null : accentHue;

  const id = 'orb_' + seed.toString(36);

  return `
  <svg width="${size}" height="${size}" viewBox="0 0 100 100" class="dual-orb" id="${id}">
    <defs>
      <radialGradient id="${id}_core">
        <stop offset="0%" stop-color="${usePrimary || `hsl(${h1},100%,65%)`}"/>
        <stop offset="60%" stop-color="${usePrimary || `hsl(${h2},90%,40%)`}"/>
        <stop offset="100%" stop-color="${usePrimary || `hsl(${h2},100%,10%)`}" stop-opacity="0"/>
      </radialGradient>

      <linearGradient id="${id}_ring">
        <stop offset="0%" stop-color="${usePrimary || `hsl(${h1},100%,75%)`}"/>
        <stop offset="100%" stop-color="${usePrimary || `hsl(${h2},100%,55%)`}"/>
      </linearGradient>
    </defs>

    <!-- base -->
    <circle cx="50" cy="50" r="46" fill="var(--bg, #05070c)"/>

    <!-- pulse -->
    <circle cx="50" cy="50" r="38"
      fill="none"
      stroke="url(#${id}_ring)"
      stroke-width="1"
      class="orb-pulse"/>

    <!-- glow -->
    <circle cx="50" cy="50" r="42"
      fill="url(#${id}_core)"
      class="orb-glow"/>

    <!-- ring -->
    <circle cx="50" cy="50" r="46"
      fill="none"
      stroke="url(#${id}_ring)"
      stroke-width="2.5"
      stroke-dasharray="70 20 10 30"
      stroke-linecap="round"
      class="orb-ring"
      opacity="0.85"/>

    <!-- core -->
    <circle cx="50" cy="50" r="8" fill="#fff" opacity="0.3" filter="blur(2px)"/>
    <circle cx="50" cy="50" r="3" fill="#fff" opacity="0.8"/>
  </svg>
  `;
}

window.makeOrbAvatar = makeOrbAvatar;</script>

