            if (sc) {
              sc.getDuration((dur) => {
                sc.seekTo(pctDec * dur); // SC aceita milissegundos
              });
            }
          };

          // Ligar os eventos do Slider
          if (mainProgress) {
            const handleDragStart = () => { isDragging = true; };

            const handleDragEnd = () => {
              if (!isDragging) return;
              isDragging = false;
              performSeek(parseFloat(mainProgress.value));
            };

            const handleDragMove = () => {
              if (isDragging && activeDuration > 0) {
                const currentSec = (parseFloat(mainProgress.value) / 100) * activeDuration;
                updateTimeUI(currentSec, activeDuration);
              }
            };

            // Eventos Desktop
            mainProgress.addEventListener('mousedown', handleDragStart);
            mainProgress.addEventListener('mouseup', handleDragEnd);
            mainProgress.addEventListener('change', handleDragEnd);

            // Eventos Mobile/Touch
            mainProgress.addEventListener('touchstart', handleDragStart, { passive: true });
            mainProgress.addEventListener('touchend', handleDragEnd);

            // Durante o arrasto (atualizar texto)
            mainProgress.addEventListener('input', handleDragMove);
          }

          // Ligar o clique na mini-barra do footer (quando minimizado)
          if (footerClick) {
            footerClick.addEventListener('click', (e) => {
              const rect = footerClick.getBoundingClientRect();
              const x = e.clientX - rect.left;
              const percent = (x / rect.width) * 100;

              if (footerBar) footerBar.style.width = `${percent}%`;

              if (mainProgress) {
                // Atualiza o slider principal escondido contornando o nosso bloqueio
                const originalDescriptor = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value');
                originalDescriptor.set.call(mainProgress, percent);
              }

              performSeek(percent);
            });
          }

        }, 1500); // Fim do setTimeout
      });
